-- Helper: check if a URI matches any pattern in a list
local function uri_matches_any(uri, patterns)
    for _, pattern in ipairs(patterns) do
        if string.find(uri, pattern, 1, true) then
            return true
        end
    end
    return false
end

-- Helper: decode a base64url-encoded string
local function base64url_decode(input)
    local remainder = #input % 4
    if remainder > 0 then
        input = input .. string.rep("=", 4 - remainder)
    end
    input = input:gsub("-", "+"):gsub("_", "/")
    return ngx.decode_base64(input)
end

-- Validate and decode a simple JWT-like token (header.payload.signature)
local function validate_token(token)
    if not token or token == "" then
        return nil, "Token is missing or empty"
    end

    -- Split token into parts
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        parts[#parts + 1] = part
    end

    if #parts ~= 3 then
        return nil, "Invalid token format: expected 3 parts"
    end

    local header_b64 = parts[1]
    local payload_b64 = parts[2]
    local signature_b64 = parts[3]

    -- Verify signature using HMAC-SHA256
    local signing_input = header_b64 .. "." .. payload_b64
    local expected_signature = ngx.encode_base64(ngx.hmac_sha1(AUTH_SECRET, signing_input))
    -- Normalize: strip padding and convert to base64url
    expected_signature = expected_signature:gsub("+", "-"):gsub("/", "_"):gsub("=", "")
    local provided_signature = signature_b64:gsub("=", "")

    if expected_signature ~= provided_signature then
        return nil, "Invalid token signature"
    end

    -- Decode payload
    local payload_json = base64url_decode(payload_b64)
    if not payload_json then
        return nil, "Failed to decode token payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "Failed to parse token payload: " .. (err or "unknown error")
    end

    -- Check token expiration
    if payload.exp then
        local now = ngx.time()
        if now > payload.exp then
            return nil, "Token has expired"
        end
    end

    -- Check required fields
    if not payload.sub then
        return nil, "Token missing 'sub' (subject) field"
    end

    if not payload.role then
        return nil, "Token missing 'role' field"
    end

    return payload, nil
end

-- Check if a user role has permission to access a given URI
local function check_role_permission(role, uri)
    local permissions = role_permissions[role]
    if not permissions then
        return false, "Unknown role: " .. tostring(role)
    end

    for _, allowed_path in ipairs(permissions) do
        -- Check if the requested URI starts with or contains the allowed path
        if string.find(uri, "^" .. allowed_path) then
            return true, nil
        end
    end

    return false, "Role '" .. role .. "' does not have permission to access '" .. uri .. "'"
end

-- Determine if the endpoint requires admin or API-level permission checks
local function requires_elevated_checks(uri)
    if string.find(uri, "/admin", 1, true) then
        return true, "admin"
    end
    if string.find(uri, "/api", 1, true) then
        return true, "api"
    end
    return false, nil
end

