    local auth_header = ngx.var.http_authorization
    local token = nil

    if auth_header then
        -- Support "Bearer <token>" format
        token = string.match(auth_header, "^[Bb]earer%s+(.+)$")
        if not token then
            -- Also try using the header value directly
            token = auth_header
        end
    end

    -- Fallback: check for token in query parameter
    if not token then
        token = ngx.var.arg_token
    end

    -- Fallback: check for token in cookie
    if not token then
        token = ngx.var.cookie_auth_token
    end

    if not token then
        ngx.log(ngx.WARN, "No authentication token provided for URI: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="Access to protected resource"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Authentication token is required"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 3: Validate the token
    local user_payload, token_err = validate_token(token)
    if not user_payload then
        ngx.log(ngx.WARN, "Token validation failed for URI: ", uri, " Error: ", token_err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Invalid authentication token: " .. token_err
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    local user_id = user_payload.sub
    local user_role = user_payload.role

    ngx.log(ngx.INFO, "Authenticated user: ", user_id, " Role: ", user_role, " URI: ", uri)

    -- Set user info in request context for downstream use
    ngx.var.authenticated_user = user_id or ""
    ngx.req.set_header("X-User-ID", user_id)
    ngx.req.set_header("X-User-Role", user_role)

    -- Step 4: Check if the URI requires elevated (admin/API) permission checks
    local needs_elevated, endpoint_type = requires_elevated_checks(uri)

    if needs_elevated then
        ngx.log(ngx.INFO, "Elevated permission check required (", endpoint_type, ") for URI: ", uri)

        -- For admin endpoints, require admin or superadmin role
        if endpoint_type == "admin" then
            if not string.match(user_role, "^super?admin$") then
                ngx.log(ngx.WARN, "Access denied: user ", user_id, " with role '", user_role,
                    "' attempted to access admin endpoint: ", uri)
                ngx.status = ngx.HTTP_FORBIDDEN
                ngx.header["Content-Type"] = "application/json"
                ngx.say(cjson.encode({
